-- Auto-generated from XLSX: import_pracownik_from_xlsx.py
-- Columns limited to existing app fields: nr, imie_nazwisko, telefon, email, is_active
BEGIN;

CREATE TEMP TABLE tmp_pracownik_import (
  nr text,
  imie_nazwisko text,
  telefon text,
  email text,
  is_active boolean
) ON COMMIT DROP;

;

SELECT
  s.nr,
  s.imie_nazwisko,
  s.telefon,
  CASE
    WHEN NULLIF(trim(coalesce(s.email, '')), '') IS NULL THEN NULL
    WHEN EXISTS (
      SELECT 1
      FROM tmp_pracownik_import d
      WHERE d.nr <> s.nr
        AND lower(trim(coalesce(d.email, ''))) = lower(trim(coalesce(s.email, '')))
    ) THEN NULL
    WHEN EXISTS (
      SELECT 1
      FROM public.pracownik p
      WHERE p.nr <> s.nr
        AND lower(trim(coalesce(p.email, ''))) = lower(trim(coalesce(s.email, '')))
    ) THEN NULL
    ELSE s.email
  END AS email,
  s.is_active
FROM tmp_pracownik_import s
ON CONFLICT (nr) DO UPDATE SET
  imie_nazwisko = EXCLUDED.imie_nazwisko,
  telefon = EXCLUDED.telefon,
  email = EXCLUDED.email,
  is_active = EXCLUDED.is_active;

COMMIT;
